// ── CARD STYLE SYSTEM ─────────────────────────────────────────────────────────
// Five named card tiers. Import these objects directly into any component.
// Never compose card styles inline — always reference this table.
const S1 = "0 1px 3px rgba(7,1,24,.06), 0 2px 8px rgba(7,1,24,.06)";
const S2 = "0 1px 3px rgba(7,1,24,.04), 0 4px 12px rgba(7,1,24,.06), 0 8px 24px rgba(7,1,24,.05)";
const S3 = "0 2px 4px rgba(7,1,24,.04), 0 6px 20px rgba(7,1,24,.07), 0 16px 40px rgba(7,1,24,.07)";

const CARD = {
  // ── Surface ─── default card on any background
  surface: {
    background:   "var(--dm-surface)",
    border:       "1px solid var(--dm-border)",
    borderRadius:  16,
    boxShadow:     S1,
  },
  // ── Raised ─── same as surface, pulled forward
  raised: {
    background:   "var(--dm-surface)",
    border:       "1px solid var(--dm-border)",
    borderRadius:  16,
    boxShadow:     S2,
  },
  // ── Dark ─── opaque dark card, used inside dark sections
  dark: {
    background:   "#070118",
    border:       "1px solid rgba(90,91,235,.15)",
    borderRadius:  16,
    boxShadow:     S2,
  },
  // ── Glass ─── violet-tinted glass wash, used for dark-surface cards
  glass: {
    background:   "linear-gradient(135deg, rgba(90,91,235,.08) 0%, rgba(90,91,235,.03) 100%)",
    border:       "1px solid rgba(90,91,235,.18)",
    borderRadius:  16,
    boxShadow:     S1,
  },
  // ── Accent ─── glass + coloured 3 px top stripe. Pass accent colour separately.
  accent: (color = "#5A5BEB") => ({
    background:   `linear-gradient(135deg, ${color}0d 0%, ${color}05 100%)`,
    border:       `1px solid ${color}30`,
    borderRadius:  16,
    boxShadow:    `${S1}, inset 0 1px 0 rgba(255,255,255,.06)`,
    position:     "relative",
    overflow:     "hidden",   // needed only for the ::before stripe pseudo — replicate with a child div
  }),
  // ── Section ─── outer section wrappers (borderRadius:20, S2)
  section: {
    background:   "var(--dm-surface)",
    border:       "1px solid var(--dm-border)",
    borderRadius:  20,
    boxShadow:     S2,
  },
  // ── Section Dark ─── dark outer wrapper (used for Deffo, Glass Hero, etc.)
  sectionDark: {
    background:   "#070118",
    border:       "1px solid rgba(90,91,235,.18)",
    borderRadius:  20,
    boxShadow:     S3,
  },
};

