function SectionPortfolio() {
  const allocs = [
    { label:"Invoice Finance", pct:38, color:"#5A5BEB" },
    { label:"Trade Finance",   pct:24, color:"#E1A325" },
    { label:"Fixed Income",    pct:20, color:"#8182EF" },
    { label:"Credit",          pct:11, color:"#28A66B" },
    { label:"ESG",             pct:7,  color:"#8182EF" },
  ];
  let offset = 0;
  const r = 60, cx = 80, cy = 80, circ = 2 * Math.PI * r;
  return (
    <div>
      <SectionLabel eyebrow="UI App" title="Portfolio Allocation" desc="Donut chart for pool/asset allocation display. DEFACTOR's portfolio UX uses violet as the primary segment." />
      <div style={{ display:"flex", gap:48, alignItems:"center", flexWrap:"wrap" }}>
        <svg width={160} height={160} viewBox="0 0 160 160">
          {allocs.map(a => {
            const len = (a.pct / 100) * circ;
            const o = offset;
            offset += len;
            return (
              <circle key={a.label} cx={cx} cy={cy} r={r} fill="none" stroke={a.color} strokeWidth={20}
                strokeDasharray={`${len} ${circ - len}`} strokeDashoffset={-o + circ * 0.25}
                style={{ transform:"rotate(-90deg)", transformOrigin:`${cx}px ${cy}px` }} />
            );
          })}
          <text x={cx} y={cy-8} textAnchor="middle" fill="var(--dm-ink)" fontSize={22} fontWeight={700}>$1.1B</text>
          <text x={cx} y={cy+12} textAnchor="middle" fill="#9CA3AF" fontSize={11}>Protocol TVL</text>
        </svg>
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {allocs.map(a => (
            <div key={a.label} style={{ display:"flex", alignItems:"center", gap:12 }}>
              <div style={{ width:12, height:12, borderRadius:3, background:a.color, flexShrink:0 }} />
              <span style={{ fontSize:13, color:"var(--dm-ink)", fontWeight:500, minWidth:120 }}>{a.label}</span>
              <span style={{ fontSize:14, fontWeight:700, color:"var(--dm-ink)" }}>{a.pct}%</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

