function SectionKYC() {
  const statuses = [
    { label:"KYC Verified",  status:"verified", icon:"M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z", color:"#28A66B", bg:"rgba(40,166,107,.1)",  border:"rgba(40,166,107,.3)",  desc:"Full access. Reg D & Reg S pools available." },
    { label:"KYC Pending",   status:"pending",  icon:"M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z",                                                                                                                                                                                                                                        color:"#E1A325", bg:"rgba(225,163,37,.1)", border:"rgba(225,163,37,.3)", desc:"Identity check in progress. Usually 24–48 hours." },
    { label:"KYC Required",  status:"required", icon:"M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z",                                                                                                                                               color:"#D3194E", bg:"rgba(211,25,78,.1)",  border:"rgba(211,25,78,.3)",  desc:"Submit documents to unlock institutional pools." },
    { label:"KYC Expired",   status:"expired",  icon:"M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15",                                                                                                                                                                       color:"#E1A325", bg:"rgba(225,163,37,.1)", border:"rgba(225,163,37,.3)", desc:"Verification expired. Re-verify to maintain access." },
  ];

  const GlossyChip = ({ icon, color }) => (
    <div style={{ width:40, height:40, borderRadius:12, flexShrink:0, position:"relative", overflow:"hidden",
      background:[
        "linear-gradient(180deg,rgba(255,255,255,.14) 0%,rgba(255,255,255,.03) 52%,transparent 52%)",
        `linear-gradient(145deg,${color}28 0%,${color}10 100%)`,
      ].join(","),
      border:`1px solid ${color}33`,
      boxShadow:`inset 0 1px 0 rgba(255,255,255,.3), inset 0 -1px 0 rgba(0,0,0,.1), 0 2px 8px ${color}18`,
      display:"flex", alignItems:"center", justifyContent:"center" }}>
      <div style={{ position:"absolute", inset:0, background:"linear-gradient(105deg,transparent 30%,rgba(255,255,255,.08) 50%,transparent 70%)", pointerEvents:"none" }} />
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round" style={{ position:"relative", zIndex:1 }}>
        <path d={icon}/>
      </svg>
    </div>
  );

  return (
    <div>
      <SectionLabel eyebrow="Web3" title="KYC Status Strip" desc="Prominent top-of-screen status strip communicating identity verification state. Action-oriented — always includes a CTA." />
      <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
        {statuses.map(s => (
          <div key={s.status} style={{ display:"flex", alignItems:"center", gap:14, padding:"12px 16px 12px 14px", borderRadius:14, background:s.bg, border:`1px solid ${s.border}` }}>
            <GlossyChip icon={s.icon} color={s.color} />
            <div style={{ flex:1 }}>
              <span style={{ fontSize:13, fontWeight:700, color:s.color }}>{s.label}</span>
              <span style={{ fontSize:12, color:s.color, opacity:.75, marginLeft:8 }}>{s.desc}</span>
            </div>
            {s.status !== "verified" && (
              <button style={{ fontFamily:"Sora,sans-serif", fontWeight:700, fontSize:12, borderRadius:100, border:"none", background:s.color, color:"#fff", padding:"7px 16px", cursor:"pointer", whiteSpace:"nowrap", boxShadow:`0 2px 8px ${s.color}33` }}>
                {s.status === "pending" ? "Track Status" : s.status === "expired" ? "Re-verify" : "Start KYC"}
              </button>
            )}
          </div>
        ))}
      </div>
      <div style={{ marginTop:16 }}>
        <DeffoChip msg="What documents do I need for Reg D pools?" accent="#5A5BEB" />
      </div>
    </div>
  );
}


