          <button style={{ fontFamily:"Sora,sans-serif", fontWeight:700, fontSize:14, padding:"12px 28px", borderRadius:100, border:"none", background:"#5A5BEB", color:"#fff", cursor:"pointer", boxShadow:"0 2px 10px rgba(90,91,235,.22), 0 4px 20px rgba(90,91,235,.12)" }}>Explore Pools →</button>
