function SectionAnnouncementBar({ isDark = false }) {
  const [dismissed, setDismissed] = useState([]);

  // Mini glossy tile — same formula as icon browser
  const IconTile = ({ path, accent, onDark }) => (
    <div style={{
      width:30, height:30, borderRadius:8, flexShrink:0,
      position:"relative", overflow:"hidden",
      background:[
        "linear-gradient(180deg, rgba(255,255,255,.18) 0%, rgba(255,255,255,.04) 52%, transparent 52%)",
        `linear-gradient(145deg, ${accent}38 0%, ${accent}14 100%)`,
      ].join(","),
      border:`1px solid ${onDark ? "rgba(255,255,255,.18)" : accent+"33"}`,
      boxShadow:[
        "inset 0 1px 0 rgba(255,255,255,.3)",
        "inset 0 -1px 0 rgba(0,0,0,.15)",
        `0 2px 8px ${accent}30`,
      ].join(","),
      display:"flex", alignItems:"center", justifyContent:"center",
    }}>
      <div style={{ position:"absolute", inset:0, background:"linear-gradient(105deg, transparent 30%, rgba(255,255,255,.08) 50%, transparent 70%)", pointerEvents:"none" }} />
      <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
        stroke={onDark ? "#fff" : accent}
        strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"
        style={{ position:"relative", zIndex:1 }}>
        <path d={path}/>
      </svg>
    </div>
  );

  const BARS = [
    { id:"a", bg:"linear-gradient(90deg,#5A5BEB,#8182EF)", accent:"#8182EF", onDark:true,  icon:"M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0", text:"Pacific Logistics Pool is now live — 12.4% APY, 60-day term.", cta:"Invest now", ctaBg:"rgba(255,255,255,.2)", ctaC:"#fff", textC:"#fff" },
    { id:"b", bg:"#070118", border:"1px solid rgba(90,91,235,.3)", accent:"#8182EF", onDark:true,  icon:"M2 12a10 10 0 1020 0a10 10 0 10-20 0M12 16v-5M11 8a1 1 0 102 0a1 1 0 10-2 0", text:"Protocol v2.4 deployed on Base mainnet. Gas fees reduced by 80%.", cta:"Read more", ctaBg:"rgba(90,91,235,.2)", ctaC:"#8182EF", textC:"rgba(240,240,253,.85)" },
    { id:"c", bg:"rgba(225,163,37,.1)", border:"1px solid rgba(225,163,37,.25)", accent:"#E1A325", onDark:false, icon:"M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0zM12 9v4m0 4h.01", text:"Apex Trade Receivables pool is 92% full. Deposits close in 48 hours.", cta:"Deposit now", ctaBg:"rgba(225,163,37,.2)", ctaC:"#E1A325", textC:"var(--dm-ink)" },
  ];
  return (
    <div>
      <SectionLabel eyebrow="Website" title="Announcement Bar"
        desc="Top-of-page persistent banner for protocol events, new pool launches, and warnings. Three severity variants: promotional (violet), neutral (dark), and warning (amber). Always dismissible." />
      <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:28 }}>
        {BARS.filter(b=>!dismissed.includes(b.id)).map(bar=>(
          <div key={bar.id} style={{ borderRadius:12, border:bar.border||"none" }}>
            <div style={{ background:bar.bg, padding:"12px 20px", display:"flex", alignItems:"center", gap:16 }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, flex:1 }}>
                <IconTile path={bar.icon} accent={bar.accent} onDark={bar.onDark} />
                <p style={{ fontSize:13, fontWeight:600, color:bar.textC, margin:0 }}>{bar.text}</p>
              </div>
              <button style={{ fontFamily:"Sora,sans-serif", fontWeight:700, fontSize:12, padding:"6px 14px", borderRadius:100, border:"none", background:bar.ctaBg, color:bar.ctaC, cursor:"pointer", whiteSpace:"nowrap", flexShrink:0 }}>{bar.cta}</button>
              <button onClick={()=>setDismissed(d=>[...d,bar.id])}
                style={{ background:"none", border:"none", cursor:"pointer", color:bar.textC, opacity:.6, padding:4, display:"flex", alignItems:"center", flexShrink:0 }}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
              </button>
            </div>
          </div>
        ))}
        {dismissed.length === BARS.length && <p style={{ fontSize:13, color:"var(--dm-muted)", fontStyle:"italic" }}>All Banners Dismissed — Reload to Reset.</p>}
      </div>
    </div>
  );
}

function SectionPricingCards({ isDark = false }) {
  const [billing, setBilling] = useState("pool");
  const PLANS = [
    { name:"Open Pool", color:"#5A5BEB", min:"$1,000", fee:"0.5%", apy:"8–11%", features:["Standard KYC","Open pools only","USDC & USDT","Monthly yield","Email support"], recommended:false },
    { name:"Reg D Pool", color:"#E1A325", min:"$10,000", fee:"0.5%", apy:"10–14%", features:["Enhanced KYC","Reg D compliant","All stablecoins","Weekly yield","Priority support","Compliance reports"], recommended:true },
    { name:"Institutional", color:"#28A66B", min:"Custom", fee:"Negotiated", apy:"Custom", features:["Full institutional onboarding","Private pool access","Custom reporting","Daily yield options","Dedicated AM","White-label available"], recommended:false },
  ];
  return (
    <div>
      <SectionLabel eyebrow="Website" title="Pricing Cards"
        desc="Three-tier pool access pricing. Centre card is the recommended tier — it gets the accent border, filled CTA, and a 'Most Popular' badge. Outer cards use ghost CTAs." />
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:16, marginBottom:28, alignItems:"start" }}>
        {PLANS.map((plan,i)=>(
          <div key={plan.name} style={{
            borderRadius:20, overflow:"hidden",
            border:`1.5px solid ${plan.recommended ? plan.color : "var(--dm-border)"}`,
            boxShadow:plan.recommended ? `0 8px 32px ${plan.color}25` : "0 1px 3px rgba(7,1,24,.06), 0 2px 8px rgba(7,1,24,.06)",
            position:"relative",
          }}>
            {plan.recommended && (
              <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:`linear-gradient(90deg,${plan.color},${plan.color}88)` }} />
            )}
            {plan.recommended && (
              <div style={{ position:"absolute", top:16, right:16, fontSize:10, fontWeight:700, padding:"3px 10px", borderRadius:100, background:`${plan.color}18`, color:plan.color, border:`1px solid ${plan.color}33` }}>Most Popular</div>
            )}
            <div style={{ padding:"28px 24px", background:plan.recommended ? `linear-gradient(145deg,${plan.color}08,transparent)` : "var(--dm-surface)" }}>
              <p style={{ fontSize:11, fontWeight:700, color:plan.color, textTransform:"uppercase", letterSpacing:".1em", marginBottom:8 }}>{plan.name}</p>
              <div style={{ marginBottom:6 }}>
                {plan.min !== "Custom" && <span style={{ fontSize:13, color:"var(--dm-muted)" }}>From </span>}
                <span style={{ fontSize:28, fontWeight:700, color:plan.min === "Custom" ? plan.color : "var(--dm-ink)", letterSpacing:"-.02em" }}>{plan.min}</span>
                {plan.min !== "Custom" && <span style={{ fontSize:12, color:"var(--dm-muted)" }}> USDC</span>}
              </div>
              {plan.apy !== "Custom" && <p style={{ fontFamily:"Space Grotesk,sans-serif", fontSize:22, fontWeight:700, color:plan.color, marginBottom:4 }}>{plan.apy}</p>}
              <p style={{ fontSize:11, color:"var(--dm-muted)", marginBottom:20 }}>{plan.apy !== "Custom" ? `APY · ${plan.fee} protocol fee` : "APY · Negotiated protocol fee"}</p>
              <button style={{ width:"100%", fontFamily:"Sora,sans-serif", fontWeight:700, fontSize:13, padding:"11px", borderRadius:100, border:`1.5px solid ${plan.color}`, background:plan.recommended ? plan.color : "transparent", color:plan.recommended ? "#fff" : plan.color, cursor:"pointer", boxShadow:plan.recommended ? `0 4px 14px ${plan.color}35` : "none", marginBottom:20 }}>
                {plan.min === "Custom" ? "Contact us" : "Get started"}
              </button>
              <div style={{ borderTop:"1px solid var(--dm-divider)", paddingTop:16 }}>
                {plan.features.map(f=>(
                  <div key={f} style={{ display:"flex", gap:8, alignItems:"center", marginBottom:10 }}>
                    <div style={{ width:16, height:16, borderRadius:"50%", background:`${plan.color}15`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                      <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke={plan.color} strokeWidth="3" strokeLinecap="round"><path d="M20 6L9 17l-5-5"/></svg>
                    </div>
                    <span style={{ fontSize:12, color:"var(--dm-muted)" }}>{f}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

