function SectionNumberedSteps({ isDark = false }) {
  const [active, setActive] = useState(null);
  const [hov, setHov] = useState(null);
  const STEPS = [
    { n:"01", title:"Connect Your Wallet", body:"Link MetaMask, WalletConnect, or Coinbase Wallet. Your address is your identity — no email required.", color:"#8182EF" },
    { n:"02", title:"Complete KYC Once",   body:"Verify your identity in under 3 minutes. One verification unlocks every pool, globally, forever.", color:"#6B6CF0" },
    { n:"03", title:"Choose a Pool",       body:"Browse 148 active pools by yield, term, and asset type. Filter by chain, currency, and compliance level.", color:"#5A5BEB" },
    { n:"04", title:"Invest and Earn",     body:"Confirm your investment on-chain. Yield credits to your wallet weekly. Withdraw at maturity.", color:"#4A4BDB" },
  ];

  // Exact icon-tile gloss formula
  const tile = (color, active) => ({
    background: [
      "linear-gradient(180deg, rgba(255,255,255,.18) 0%, rgba(255,255,255,.04) 52%, transparent 52%)",
      `linear-gradient(145deg, ${color}${active?"40":"28"} 0%, ${color}${active?"18":"10"} 100%)`,
    ].join(","),
    border: `1px solid ${active ? color+"55" : "rgba(255,255,255,.13)"}`,
    boxShadow: [
      "inset 0 1px 0 rgba(255,255,255,.35)",
      "inset 0 -1px 0 rgba(0,0,0,.2)",
      `0 ${active?8:4}px ${active?20:12}px ${color}${active?"40":"22"}`,
    ].join(","),
  });

  return (
    <div>
      <SectionLabel eyebrow="Website" title="Numbered Steps"
        desc="Vertical numbered process with expandable detail. Used for onboarding flows and how-it-works sections. Step numbers use the icon-tile gloss formula — they anchor the reading eye and create clear sequence." />
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:24, marginBottom:28 }}>
        <div>
          {STEPS.map((step,i)=>{
            const isActive = active===i;
            const isHov = hov===i && !isActive;
            return (
              <div key={step.n}
                onClick={()=>setActive(isActive?null:i)}
                onMouseEnter={()=>setHov(i)}
                onMouseLeave={()=>setHov(null)}
                style={{ display:"flex", gap:16, padding:"14px 12px", borderRadius:12, borderBottom:i<STEPS.length-1?"1px solid var(--dm-divider)":"none", cursor:"pointer", alignItems:"center", transition:"background .15s", background: isActive ? `${step.color}08` : isHov ? "rgba(90,91,235,.04)" : "transparent" }}>
                {/* Icon-tile number badge */}
                <div style={{ flexShrink:0, width:56, height:56, borderRadius:16, position:"relative", overflow:"hidden", transition:"all .18s", ...tile(step.color, isActive || isHov) }}>
                  {/* Shimmer diagonal */}
                  <div style={{ position:"absolute", inset:0, background:"linear-gradient(105deg, transparent 25%, rgba(255,255,255,.1) 50%, transparent 75%)", pointerEvents:"none" }} />
                  <div style={{ width:"100%", height:"100%", display:"flex", alignItems:"center", justifyContent:"center" }}>
                    <span style={{ fontFamily:"Sora,sans-serif", fontVariantNumeric:"tabular-nums", fontSize:16, fontWeight:800, color:isActive||isHov?"#fff":step.color, lineHeight:1, position:"relative", zIndex:1, letterSpacing:"-.02em" }}>{step.n}</span>
                  </div>
                </div>
                <div style={{ flex:1, alignSelf: isActive ? "flex-start" : "auto", paddingTop: isActive ? 3 : 0 }}>
                  <p style={{ fontSize:14, fontWeight:700, color:"var(--dm-ink)", marginBottom:isActive?8:0, transition:"margin .15s" }}>{step.title}</p>
                  {isActive && <p style={{ fontSize:13, color:"var(--dm-muted)", lineHeight:1.65 }}>{step.body}</p>}
                </div>
              </div>
            );
          })}
        </div>
        {/* Detail panel */}
        <div style={{ background:"#070118", borderRadius:20, padding:"36px 32px", display:"flex", flexDirection:"column", justifyContent:"center", position:"relative", border:"1px solid rgba(90,91,235,.15)", boxShadow:"inset 0 1px 0 rgba(255,255,255,.05)" }}>
          <div style={{ position:"absolute", top:"-20%", right:"-10%", width:240, height:240, borderRadius:"50%", background:"radial-gradient(circle,rgba(90,91,235,.22),transparent 65%)", pointerEvents:"none" }} />
          <div style={{ position:"absolute", inset:0, backgroundImage:"linear-gradient(rgba(90,91,235,.04) 1px,transparent 1px),linear-gradient(90deg,rgba(90,91,235,.04) 1px,transparent 1px)", backgroundSize:"28px 28px", pointerEvents:"none" }} />
          {active !== null ? (
            <div style={{ position:"relative", zIndex:1 }}>
              {/* Big glossy number */}
              <div style={{ display:"inline-block", marginBottom:20, ...tile(STEPS[active].color, true), borderRadius:20, padding:"12px 20px" }}>
                <span style={{ fontFamily:"Space Grotesk,sans-serif", fontVariantNumeric:"tabular-nums", fontSize:52, fontWeight:800, color:"#fff", lineHeight:1, letterSpacing:"-.03em" }}>{STEPS[active].n}</span>
              </div>
              <p style={{ fontSize:22, fontWeight:700, color:"#F0F0FD", letterSpacing:"-.02em", lineHeight:1.15, marginBottom:12 }}>{STEPS[active].title}</p>
              <p style={{ fontSize:14, color:"rgba(240,240,253,.55)", lineHeight:1.75 }}>{STEPS[active].body}</p>
            </div>
          ) : (
            <div style={{ position:"relative", zIndex:1 }}>
              <div style={{ display:"flex", gap:10, marginBottom:20 }}>
                {STEPS.map(s=>(
                  <div key={s.n} style={{ width:44, height:44, borderRadius:12, ...tile(s.color, false), display:"flex", alignItems:"center", justifyContent:"center" }}>
                    <span style={{ fontFamily:"Sora,sans-serif", fontVariantNumeric:"tabular-nums", fontSize:13, fontWeight:800, color:s.color }}>{s.n}</span>
                  </div>
                ))}
              </div>
              <p style={{ fontSize:28, fontWeight:700, color:"rgba(240,240,253,.18)", lineHeight:1.15 }}>Click a step<br/>to preview.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function SectionStatCountUp({ isDark = false }) {
  const [animated, setAnimated] = useState(false);
  const [vals, setVals] = useState({ tvl:2.41, pools:148, investors:6820, apy:11.2 });
  const [animating, setAnimating] = useState(false);
  function runAnimation() {
    setAnimating(true);
    setVals({ tvl:0, pools:0, investors:0, apy:0 });
    setTimeout(() => {
      const targets = { tvl:2.41, pools:148, investors:6820, apy:11.2 };
      const duration = 1800;
      const start = Date.now();
      const tick = () => {
        const elapsed = Date.now() - start;
        const progress = Math.min(elapsed/duration, 1);
        const ease = 1 - Math.pow(1-progress,3);
        setVals({
          tvl:    +(targets.tvl    * ease).toFixed(2),
          pools:  Math.round(targets.pools    * ease),
          investors: Math.round(targets.investors * ease),
          apy:    +(targets.apy    * ease).toFixed(1),
        });
        if (progress < 1) requestAnimationFrame(tick);
        else setAnimating(false);
      };
      requestAnimationFrame(tick);
    }, 50);
  }
  return (
    <div>
      <SectionLabel eyebrow="Website" title="Stat Count-Up"
        desc="Animated count-up numbers triggered on scroll or page load. Cubic ease-out over 1.8 seconds. Creates a moment of delight and draws attention to key metrics. Used in hero sections and landing pages." />
      <div style={{ borderRadius:20, border:"1px solid var(--dm-border)", marginBottom:28, boxShadow:"0 1px 3px rgba(7,1,24,.04), 0 4px 12px rgba(7,1,24,.06), 0 8px 24px rgba(7,1,24,.05)" }}>
        <div style={{ background:"linear-gradient(135deg,#070118 0%,#1a0a40 50%,#0d1a30 100%)", padding:"56px 48px", position:"relative", overflow:"hidden" }}>
          <div style={{ position:"absolute", inset:0, backgroundImage:"radial-gradient(circle,rgba(90,91,235,.08) 1px,transparent 1px)", backgroundSize:"24px 24px" }} />
          <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:0, position:"relative", zIndex:1 }}>
            {[
              { label:"Total Value Locked", value:`$${vals.tvl.toFixed(2)}B`, accent:"#8182EF" },
              { label:"Active Pools",       value:String(vals.pools),          accent:"#5A5BEB" },
              { label:"Total Investors",    value:vals.investors.toLocaleString(), accent:"#28A66B" },
              { label:"Average APY",        value:`${vals.apy.toFixed(1)}%`,   accent:"#E1A325" },
            ].map((s,i,arr)=>(
              <div key={s.label} style={{ textAlign:"center", padding:"0 8px", borderRight:i<arr.length-1?"1px solid rgba(255,255,255,.07)":"none", minWidth:0 }}>
                <p style={{ fontSize:34, fontWeight:700, letterSpacing:"-.03em", color:"#fff", lineHeight:1, marginBottom:8, fontFamily:"Space Grotesk,sans-serif", fontVariantNumeric:"tabular-nums", fontFeatureSettings:'"tnum"', whiteSpace:"nowrap" }}>{s.value}</p>
                <p style={{ fontSize:11, fontWeight:700, color:s.accent, textTransform:"uppercase", letterSpacing:".1em" }}>{s.label}</p>
              </div>
            ))}
          </div>
        </div>
        <div style={{ background:"var(--dm-surface)", padding:"14px 24px", borderTop:"1px solid var(--dm-border)", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <p style={{ fontSize:12, color:"var(--dm-muted)" }}>Numbers animate in on scroll using cubic-bezier ease-out over 1.8 seconds.</p>
          <button onClick={runAnimation}
            style={{ fontFamily:"Sora,sans-serif", fontWeight:600, fontSize:12, padding:"7px 16px", borderRadius:100, border:"1px solid var(--dm-border)", background:"transparent", color:"var(--dm-muted)", cursor:"pointer" }}>
            ▶ Replay animation
          </button>
        </div>
      </div>
    </div>
  );
}

