function SectionGlassmorphism({ isDark = false }) {
  const levels = [
    { name:"L1 — Subtle",  blur:6,  bg:"rgba(255,255,255,.04)", border:"rgba(255,255,255,.08)", label:"Ambient backgrounds, section wash" },
    { name:"L2 — Mid",     blur:12, bg:"rgba(255,255,255,.07)", border:"rgba(255,255,255,.12)", label:"Cards, panels, primary containers" },
    { name:"L3 — Strong",  blur:20, bg:"rgba(255,255,255,.11)", border:"rgba(255,255,255,.18)", label:"Modals, drawers, elevated surfaces" },
    { name:"L4 — Intense", blur:32, bg:"rgba(255,255,255,.16)", border:"rgba(255,255,255,.24)", label:"Tooltips, popovers, top-layer UI" },
  ];
  const rules = [
    [true,  "Always place over a coloured or blurred background — glass is invisible on flat white or black"],
    [true,  "Use backdrop-filter: blur() not box-shadow blur — box-shadow does not blur content behind"],
    [true,  "Keep border opacity between .08 and .24 — the top edge catches light, the rest recedes"],
    [true,  "Pair with a 1px inset top highlight: inset 0 1px 0 rgba(255,255,255,.18)"],
    [false, "Stack glass on glass — nested blur layers compound GPU cost and look muddy"],
    [false, "Use on interactive elements that need high contrast — glass fails WCAG AA at small sizes"],
    [false, "Apply blur values above 32px — diminishing returns and significant performance cost"],
  ];
  return (
    <div>
      <SectionLabel eyebrow="Patterns · Glass & Depth" title="Glassmorphism"
        desc="Frosted-glass surfaces built from backdrop-filter blur, semi-transparent fills, and hairline borders. Four calibrated levels — choose by elevation, not preference." />

      {/* Level demos */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:16, marginBottom:32,
        background:"linear-gradient(135deg,#5A5BEB 0%,#070118 50%,#28A66B 100%)",
        borderRadius:20, padding:28 }}>
        {levels.map(l => (
          <div key={l.name} style={{ backdropFilter:`blur(${l.blur}px)`, WebkitBackdropFilter:`blur(${l.blur}px)`,
            background:l.bg, border:`1px solid ${l.border}`,
            boxShadow:"inset 0 1px 0 rgba(255,255,255,.18)", borderRadius:16, padding:24 }}>
            <div style={{ fontSize:11, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase",
              color:"rgba(255,255,255,.5)", marginBottom:8 }}>{l.name}</div>
            <div style={{ fontSize:13, fontWeight:600, color:"#fff", marginBottom:6 }}>blur({l.blur}px)</div>
            <div style={{ fontSize:11, color:"rgba(255,255,255,.55)", lineHeight:1.5 }}>{l.label}</div>
            <div style={{ marginTop:14, fontSize:10, fontFamily:"monospace", color:"rgba(255,255,255,.4)",
              background:"rgba(0,0,0,.2)", borderRadius:6, padding:"5px 8px", lineHeight:1.7 }}>
              blur: {l.blur}px<br/>
              bg: {l.blur <= 12 ? "04" : l.blur <= 20 ? "07" : l.blur <= 32 ? "11" : "16"}% white<br/>
              border: {l.blur <= 12 ? "08" : l.blur <= 20 ? "12" : l.blur <= 32 ? "18" : "24"}% white
            </div>
          </div>
        ))}
      </div>

      {/* Specs */}
      <Sub>CSS Formula</Sub>
      <div style={{ background:"var(--dm-surface)", border:"1px solid var(--dm-border)", borderRadius:12,
        padding:"16px 20px", marginBottom:28, fontFamily:"monospace", fontSize:12,
        color:"#8182EF", lineHeight:2 }}>
        backdrop-filter: blur(12px);<br/>
        background: rgba(255,255,255,.07);<br/>
        border: 1px solid rgba(255,255,255,.12);<br/>
        box-shadow: inset 0 1px 0 rgba(255,255,255,.18);
      </div>

      {/* Rules */}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:20 }}>
        <div>
          <Sub>Do</Sub>
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {rules.filter(([ok])=>ok).map(([,rule])=>(
              <div key={rule} style={{ display:"flex", gap:10, padding:"11px 14px", borderRadius:10,
                background:"rgba(40,166,107,.05)", border:"1px solid rgba(40,166,107,.2)" }}>
                <span style={{ fontSize:13, fontWeight:700, color:"#28A66B", flexShrink:0 }}>✓</span>
                <span style={{ fontSize:12, color:"var(--dm-ink)", lineHeight:1.5 }}>{rule}</span>
              </div>
            ))}
          </div>
        </div>
        <div>
          <Sub>Don't</Sub>
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {rules.filter(([ok])=>!ok).map(([,rule])=>(
              <div key={rule} style={{ display:"flex", gap:10, padding:"11px 14px", borderRadius:10,
                background:"rgba(211,25,78,.05)", border:"1px solid rgba(211,25,78,.2)" }}>
                <span style={{ fontSize:13, fontWeight:700, color:"#D3194E", flexShrink:0 }}>✕</span>
                <span style={{ fontSize:12, color:"var(--dm-ink)", lineHeight:1.5 }}>{rule}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}


