// ── APP ───────────────────────────────────────────────────────────────────────
export default function App() {
  const [isDark, setIsDark] = useState(false);
  const [activeSection, setActiveSection] = useState(ALL_ITEMS[0]);
  const mainRef = useRef(null);

  useEffect(() => {
    const styleEl = document.createElement("style");
    styleEl.textContent = CSS;
    document.head.appendChild(styleEl);
    return () => document.head.removeChild(styleEl);
  }, []);

  useEffect(() => {
    document.body.classList.toggle("dark", isDark);
  }, [isDark]);

  useEffect(() => {
    const el = mainRef.current;
    if (!el) return;
    function handleScroll() {
      let active = ALL_ITEMS[0];
      for (let i = ALL_ITEMS.length - 1; i >= 0; i--) {
        const sec = document.getElementById(`sec-${ALL_ITEMS[i]}`);
        if (sec && sec.getBoundingClientRect().top <= 120) { active = ALL_ITEMS[i]; break; }
      }
      setActiveSection(active);
    }
    el.addEventListener("scroll", handleScroll);
    return () => el.removeEventListener("scroll", handleScroll);
  }, []);

  function scrollTo(id) {
    const el = document.getElementById(`sec-${id}`);
    if (el) el.scrollIntoView({ behavior:"smooth", block:"start" });
  }

  return (
    <div style={{ display:"flex", height:"100vh", overflow:"hidden", background:"var(--dm-bg)", color:"var(--dm-ink)" }}>
      {/* SIDEBAR */}
      <nav style={{ width:240, minWidth:240, background:"#070118", position:"relative", height:"100vh", overflowY:"auto", flexShrink:0, paddingBottom:48, scrollbarWidth:"none", msOverflowStyle:"none", isolation:"isolate", borderRight:"1px solid #070118" }}>
        {/* Logo */}
        <div style={{ padding:"24px 20px 20px", borderBottom:"1px solid rgba(139,92,246,.12)", marginBottom:4 }}>
          <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
            <img src={EMBLEM_PNG} alt="Defactor" style={{ display:"block", height:28, width:28, objectFit:"contain", flexShrink:0 }} />
            <span style={{ fontFamily:"Sora,sans-serif", fontWeight:700, fontSize:16, color:"#fff", letterSpacing:"-.02em", lineHeight:1 }}>defactor</span>
          </div>
          <div style={{ fontSize:10, color:"#8182EF", fontWeight:600, letterSpacing:".08em", textTransform:"uppercase" }}>Design System Q2 2026</div>
        </div>
        {/* Nav */}
        {NAV.map((chapter, ci) => (
          <div key={chapter.label}>
            <div style={{ padding:"12px 16px 8px", borderTop: ci===0?"none":"1px solid rgba(139,92,246,.1)", marginTop:ci===0?8:8 }}>
              <span style={{ fontSize:11, fontWeight:700, letterSpacing:".08em", textTransform:"uppercase", color:"rgba(255,255,255,.85)" }}>{chapter.label}</span>
            </div>
            {chapter.groups.map(g => (
              <div key={g.label}>
                <div style={{ padding:"6px 20px 3px", fontSize:10, fontWeight:500, letterSpacing:".1em", textTransform:"uppercase", color:"rgba(255,255,255,.28)" }}>{g.label}</div>
                {g.items.map(id => (
                  <button key={id} onClick={() => scrollTo(id)}
                    className={activeSection===id?"active-nav":undefined}
                    style={{ display:"flex", alignItems:"center", gap:8, width:"100%", padding:"5px 16px 5px 24px",
                      background: activeSection===id?"rgba(90,91,235,.18)":"none", border:"none", outline:"none",
                      boxShadow: activeSection===id?"inset 2px 0 0 #8182EF":"none",
                      fontSize:12.5, fontWeight: activeSection===id?600:400,
                      color: activeSection===id?"#E8E8FC":"rgba(255,255,255,.48)",
                      cursor:"pointer", textAlign:"left", lineHeight:1.4, borderRadius:"0 8px 8px 0", transition:"background .12s, color .12s, box-shadow .12s" }}>
                    {activeSection===id && <div style={{ width:5, height:5, borderRadius:"50%", background:"#8182EF", flexShrink:0 }} />}
                    {NAMES[id] || id}
                  </button>
                ))}
              </div>
            ))}
          </div>
        ))}
      </nav>

      {/* MAIN */}
      <main ref={mainRef} style={{ flex:1, overflowY:"auto", overflowX:"hidden", minWidth:0 }}>
        {/* HEADER */}
        <div style={{ position:"sticky", top:0, zIndex:100, background:"var(--dm-header)", borderBottom:"1px solid var(--dm-border)", padding:"12px 32px", display:"flex", justifyContent:"space-between", alignItems:"center", gap:16, transition:"background .2s,border-color .2s" }}>
          <div>
            <p style={{ fontSize:11, color:"var(--dm-muted)", maxWidth:540, lineHeight:1.5 }}>A single-file reference tool covering Defactor's full visual and interaction language across six tabs — Brand, Website, UI App, Web3, UX Artefacts, and Patterns — with live light/dark mode, sidebar navigation, and interactive component previews.</p>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>

            {/* Explicit segmented Light / Dark control */}
            <div style={{ display:"flex", borderRadius:100, border:"1px solid var(--dm-border)", background:"var(--dm-surf2)", padding:3, gap:2 }}>
              {[
                { label:"Light", val:false, icon:<svg width={11} height={11} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round"><circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/></svg> },
                { label:"Dark",  val:true,  icon:<svg width={11} height={11} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg> },
              ].map(opt => (
                <button key={opt.label} onClick={() => setIsDark(opt.val)}
                  style={{ fontFamily:"Sora,sans-serif", fontWeight:600, fontSize:12, padding:"5px 14px", borderRadius:100, border:"none", cursor:"pointer", display:"flex", alignItems:"center", gap:5, transition:"all .15s",
                    background: isDark===opt.val ? (isDark?"#5A5BEB":"rgba(7,1,24,.08)") : "transparent",
                    color: isDark===opt.val ? (isDark?"#fff":"var(--dm-ink)") : "var(--dm-muted)",
                    boxShadow: isDark===opt.val ? "0 1px 4px rgba(0,0,0,.12)" : "none" }}>
                  {opt.icon}{opt.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* CONTENT */}
        <div style={{ padding:"48px 56px" }}>
          {ALL_ITEMS.map((id, i) => {
            const Comp = SECTION_COMPONENTS[id];
            return (
              <div key={id}>
                <div id={`sec-${id}`} style={{ scrollMarginTop:72, contain:"layout paint" }}>
                  {Comp ? <Comp isDark={isDark} /> : <p style={{ color:"var(--dm-muted)" }}>Section: {id}</p>}
                </div>
                {i < ALL_ITEMS.length - 1 && (
                  <hr style={{ border:"none", borderTop:"2px solid var(--dm-divider)", margin:"56px 0", transition:"border-color .2s" }} />
                )}
              </div>
            );
          })}
          {/* FOOTER */}
          <div style={{ marginTop:80, paddingTop:24, borderTop:"1px solid var(--dm-border)", fontSize:12, color:"var(--dm-muted)", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <span>Defactor Design System · Q2 2026</span>
            <span>Sora · Brand Violet #5A5BEB · Protocol-grade DeFi</span>
          </div>
        </div>
      </main>
    </div>
  );
}

// ── KYC / KYB FLOW ────────────────────────────────────────────────────────────
function SectionKYCFlow() {
  const [track, setTrack] = useState("kyc");  // "kyc" | "kyb"
  const [step,  setStep]  = useState(0);

  const KYC_STEPS = [
    { id:"personal",  label:"Personal Info",    icon:"M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2M12 11a4 4 0 100-8 4 4 0 000 8z",       desc:"Full legal name, date of birth, nationality, and residential address.",            fields:["Full legal name","Date of birth","Nationality","Residential address"] },
    { id:"id",        label:"ID Document",      icon:"M10 6H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V8a2 2 0 00-2-2h-5m-4 0V5a2 2 0 114 0v1m-4 0a2 2 0 104 0",  desc:"Government-issued photo ID. Passport preferred; national ID or driver's licence accepted.", fields:["Passport / National ID","Driver's licence (alt.)","Expiry date","Issuing country"] },
    { id:"liveness",  label:"Liveness Check",   icon:"M15 10l-4 4m0 0l-4-4m4 4V3M3 21h18",                                              desc:"Short selfie video to match your ID photo. Takes under 60 seconds.",               fields:["Selfie capture","Facial match","Liveness detection","3D depth check"] },
    { id:"aml",       label:"AML Screening",    icon:"M9 12l2 2 4-4M7.835 4.697a3.42 3.42 0 001.946-.806 3.42 3.42 0 014.438 0 3.42 3.42 0 001.946.806 3.42 3.42 0 013.138 3.138 3.42 3.42 0 00.806 1.946 3.42 3.42 0 010 4.438 3.42 3.42 0 00-.806 1.946 3.42 3.42 0 01-3.138 3.138 3.42 3.42 0 00-1.946.806 3.42 3.42 0 01-4.438 0 3.42 3.42 0 00-1.946-.806 3.42 3.42 0 01-3.138-3.138 3.42 3.42 0 00-.806-1.946 3.42 3.42 0 010-4.438 3.42 3.42 0 00.806-1.946 3.42 3.42 0 013.138-3.138z", desc:"Automated PEP, sanctions, and adverse media screening. Usually instant.",           fields:["PEP check","Sanctions lists","Adverse media","Watchlist screening"] },
    { id:"complete",  label:"Verified",         icon:"M20 6L9 17l-5-5",                                                                  desc:"Identity confirmed. Reg D and Reg S pools are now accessible.",                   fields:["Reg D pools unlocked","Reg S pools unlocked","Global access","KYC valid 24 months"] },
  ];

  const KYB_STEPS = [
    { id:"entity",    label:"Entity Details",   icon:"M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-2 10v-5a1 1 0 00-1-1h-2a1 1 0 00-1 1v5m4 0H9", desc:"Legal entity name, registration number, incorporation country, and registered address.", fields:["Legal entity name","Reg. number","Incorporation country","Registered address"] },
    { id:"ubo",       label:"UBO Declaration",  icon:"M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0", desc:"Declare all Ultimate Beneficial Owners holding ≥10% of the entity.",              fields:["UBO name + DOB","Ownership %","UBO nationality","UBO ID document"] },
    { id:"docs",      label:"Entity Documents", icon:"M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z", desc:"Certificate of incorporation, memorandum, and proof of registered address.",     fields:["Certificate of incorporation","Memorandum & Articles","Proof of address","Latest audited accounts"] },
    { id:"aml",       label:"AML & Sanctions",  icon:"M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z", desc:"Entity-level sanctions screening and adverse media check on all UBOs.",         fields:["Entity sanctions check","UBO sanctions check","Adverse media","PEP screening"] },
    { id:"complete",  label:"Entity Approved",  icon:"M20 6L9 17l-5-5",                                                                  desc:"Entity verified. Institutional pools and issuer tools are now accessible.",      fields:["Institutional pools","Issuer dashboard","Reg D / Reg S","Annual renewal"] },
  ];

  const steps = track === "kyc" ? KYC_STEPS : KYB_STEPS;
  const s = steps[step];
  const VIOLET = "#5A5BEB"; const GREEN = "#28A66B"; const GOLD = "#E1A325";
  const accent = s.id === "complete" ? GREEN : VIOLET;

  // doc upload states for the ID / docs step
  const docStates = [
    { label:"Front of ID",     state:"uploaded",  name:"passport_front.jpg" },
    { label:"Back of ID",      state:"uploaded",  name:"passport_back.jpg"  },
    { label:"Proof of address",state:"pending",   name:null },
  ];

  return (
    <div>
      <SectionLabel eyebrow="Web3" title="KYC / KYB Flow"
        desc="End-to-end identity and entity verification patterns. KYC for individual retail and accredited investors; KYB for institutional entities and pool issuers. Both feed into the compliance gate that controls pool access." />

      {/* Track selector */}
      <div style={{ display:"flex", gap:8, marginBottom:24 }}>
        {[["kyc","KYC — Individual","Retail & accredited investors"],["kyb","KYB — Entity","Institutions & issuers"]].map(([key,label,sub])=>(
          <button key={key} onClick={()=>{setTrack(key);setStep(0);}}
            style={{ fontFamily:"Sora,sans-serif", flex:1, padding:"14px 20px", borderRadius:16, cursor:"pointer", border:`2px solid ${track===key?"#5A5BEB":"var(--dm-border)"}`, background:track===key?"rgba(90,91,235,.06)":"transparent", textAlign:"left", transition:"all .15s" }}>
            <p style={{ fontSize:13, fontWeight:700, color:track===key?"#5A5BEB":"var(--dm-ink)", marginBottom:2 }}>{label}</p>
            <p style={{ fontSize:11, color:"var(--dm-muted)" }}>{sub}</p>
          </button>
        ))}
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"220px 1fr", gap:0, borderRadius:20, border:"1px solid var(--dm-border)", boxShadow:"0 1px 3px rgba(7,1,24,.04), 0 4px 12px rgba(7,1,24,.06), 0 8px 24px rgba(7,1,24,.05)" }}>

        {/* Step nav sidebar */}
        <div style={{ borderRight:"1px solid var(--dm-border)", padding:"24px 0", background:"var(--dm-surface)", borderRadius:"20px 0 0 20px" }}>
          <p style={{ fontSize:10, fontWeight:700, color:"var(--dm-muted)", textTransform:"uppercase", letterSpacing:".12em", padding:"0 20px", marginBottom:16 }}>{track==="kyc"?"Identity Checks":"Entity Checks"}</p>
          {steps.map((st, i)=>{
            const done = i < step;
            const active = i === step;
            return (
              <button key={st.id} onClick={()=>setStep(i)}
                style={{ width:"100%", display:"flex", alignItems:"center", gap:12, padding:"10px 20px", border:"none", background:"transparent", cursor:"pointer", textAlign:"left",
                  borderLeft:`3px solid ${active?"#5A5BEB":"transparent"}`,
                  backgroundColor: active ? "rgba(90,91,235,.06)" : "transparent" }}>
                <div style={{ width:24, height:24, borderRadius:8, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center",
                  background: done ? "#28A66B" : active ? "#5A5BEB" : "var(--dm-surf2)",
                  border:`1px solid ${done?"#28A66B":active?"#5A5BEB":"var(--dm-border)"}` }}>
                  {done
                    ? <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3" strokeLinecap="round"><path d="M20 6L9 17l-5-5"/></svg>
                    : <span style={{ fontSize:9, fontWeight:700, color: active?"#fff":"var(--dm-muted)", fontVariantNumeric:"tabular-nums" }}>{String(i+1).padStart(2,"0")}</span>
                  }
                </div>
                <span style={{ fontSize:12, fontWeight: active||done ? 600 : 400, color: active?"#5A5BEB": done?"#28A66B":"var(--dm-muted)" }}>{st.label}</span>
              </button>
            );
          })}
          {/* Progress indicator */}
          <div style={{ margin:"20px 20px 0", padding:"12px 14px", borderRadius:12, background:"var(--dm-surf2)", border:"1px solid var(--dm-border)" }}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6 }}>
              <span style={{ fontSize:10, fontWeight:700, color:"var(--dm-muted)", textTransform:"uppercase", letterSpacing:".08em" }}>Progress</span>
              <span style={{ fontSize:10, fontWeight:700, color:"#5A5BEB" }}>{Math.round((step/( steps.length-1))*100)}%</span>
            </div>
            <div style={{ height:4, borderRadius:100, background:"var(--dm-border)" }}>
              <div style={{ height:"100%", borderRadius:100, background:"linear-gradient(90deg,#5A5BEB,#8182EF)", width:`${Math.round((step/(steps.length-1))*100)}%`, transition:"width .4s cubic-bezier(.4,0,.2,1)" }} />
            </div>
          </div>
        </div>

        {/* Step content */}
        <div style={{ padding:"32px 36px", background:"var(--dm-bg)", borderRadius:"0 20px 20px 0" }}>
          {/* Step header */}
          <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", marginBottom:24 }}>
            <div style={{ display:"flex", alignItems:"center", gap:14 }}>
              <div style={{ width:44, height:44, borderRadius:12, background: s.id==="complete"?"rgba(40,166,107,.1)":"rgba(90,91,235,.08)", border:`1px solid ${s.id==="complete"?"rgba(40,166,107,.25)":"rgba(90,91,235,.2)"}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={accent} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d={s.icon}/></svg>
              </div>
              <div>
                <h3 style={{ fontSize:18, fontWeight:700, color:"var(--dm-ink)", marginBottom:4, letterSpacing:"-.02em" }}>{s.label}</h3>
                <p style={{ fontSize:13, color:"var(--dm-muted)", lineHeight:1.5 }}>{s.desc}</p>
              </div>
            </div>
            {/* Reg badge */}
            <div style={{ display:"flex", gap:6, flexShrink:0 }}>
              {["Reg D","Reg S"].map(r=>(
                <span key={r} style={{ fontSize:10, fontWeight:700, padding:"3px 8px", borderRadius:100, background:"rgba(90,91,235,.08)", border:"1px solid rgba(90,91,235,.2)", color:"#5A5BEB" }}>{r}</span>
              ))}
            </div>
          </div>

          {/* Document upload UI (shown on doc steps) */}
          {(s.id==="id"||s.id==="docs") && (
            <div style={{ marginBottom:24 }}>
              <p style={{ fontSize:11, fontWeight:700, color:"var(--dm-muted)", textTransform:"uppercase", letterSpacing:".1em", marginBottom:12 }}>Document Upload</p>
              <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                {docStates.map(d=>(
                  <div key={d.label} style={{ display:"flex", alignItems:"center", gap:14, padding:"12px 16px", borderRadius:12, background:"var(--dm-surface)", border:`1px solid ${d.state==="uploaded"?"rgba(40,166,107,.25)":"var(--dm-border)"}` }}>
                    <div style={{ width:36, height:36, borderRadius:8, background: d.state==="uploaded"?"rgba(40,166,107,.1)":"var(--dm-surf2)", border:`1px solid ${d.state==="uploaded"?"rgba(40,166,107,.25)":"var(--dm-border)"}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                      {d.state==="uploaded"
                        ? <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#28A66B" strokeWidth="2" strokeLinecap="round"><path d="M20 6L9 17l-5-5"/></svg>
                        : <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="var(--dm-muted)" strokeWidth="1.8" strokeLinecap="round"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4M17 8l-5-5-5 5M12 3v12"/></svg>
                      }
                    </div>
                    <div style={{ flex:1 }}>
                      <p style={{ fontSize:13, fontWeight:600, color:"var(--dm-ink)", marginBottom:1 }}>{d.label}</p>
                      <p style={{ fontSize:11, color: d.state==="uploaded"?"#28A66B":"var(--dm-muted)" }}>
                        {d.state==="uploaded" ? d.name : "Tap to upload · JPG, PNG or PDF · Max 10 MB"}
                      </p>
                    </div>
                    {d.state==="pending" && (
                      <button style={{ fontFamily:"Sora,sans-serif", fontSize:12, fontWeight:600, padding:"6px 14px", borderRadius:100, border:"1px solid rgba(90,91,235,.3)", background:"rgba(90,91,235,.08)", color:"#5A5BEB", cursor:"pointer" }}>Upload</button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Data fields checklist */}
          <p style={{ fontSize:11, fontWeight:700, color:"var(--dm-muted)", textTransform:"uppercase", letterSpacing:".1em", marginBottom:12 }}>
            {s.id==="complete" ? "What's unlocked" : "Required fields"}
          </p>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:28 }}>
            {s.fields.map((f,i)=>(
              <div key={f} style={{ display:"flex", alignItems:"center", gap:10, padding:"10px 14px", borderRadius:10, background:"var(--dm-surface)", border:"1px solid var(--dm-border)" }}>
                <div style={{ width:20, height:20, borderRadius:6, background:s.id==="complete"?"rgba(40,166,107,.1)":"rgba(90,91,235,.08)", border:`1px solid ${s.id==="complete"?"rgba(40,166,107,.25)":"rgba(90,91,235,.2)"}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                  <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke={s.id==="complete"?"#28A66B":"#5A5BEB"} strokeWidth="3" strokeLinecap="round">
                    {s.id==="complete" ? <path d="M20 6L9 17l-5-5"/> : <path d="M12 4v16M4 12h16"/>}
                  </svg>
                </div>
                <span style={{ fontSize:12, color:"var(--dm-ink)", fontWeight:500 }}>{f}</span>
              </div>
            ))}
          </div>

          {/* CTA row */}
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <button onClick={()=>setStep(Math.max(0,step-1))} disabled={step===0}
              style={{ fontFamily:"Sora,sans-serif", fontSize:13, fontWeight:600, padding:"10px 20px", borderRadius:100, border:"1px solid var(--dm-border)", background:"transparent", color:"var(--dm-muted)", cursor:step===0?"default":"pointer", opacity:step===0?.3:1 }}>
              ← Back
            </button>
            <div style={{ display:"flex", gap:10, alignItems:"center" }}>
              <DeffoChip msg={s.id==="complete"?"Explore your eligible pools":"What is this step checking?"} />
              <button onClick={()=>setStep(Math.min(steps.length-1, step+1))} disabled={step===steps.length-1}
                style={{ fontFamily:"Sora,sans-serif", fontSize:13, fontWeight:700, padding:"10px 24px", borderRadius:100, border:"none", background: step===steps.length-1?"#28A66B":"#5A5BEB", color:"#fff", cursor:step===steps.length-1?"default":"pointer", opacity:step===steps.length-1?.6:1, boxShadow:"0 2px 10px rgba(90,91,235,.22), 0 4px 20px rgba(90,91,235,.12)" }}>
                {step===steps.length-1 ? "Complete" : step===steps.length-2 ? "Submit →" : "Continue →"}
              </button>
            </div>
          </div>
        </div>

      </div>

      {/* Compliance reference table */}
      <Sub>Compliance Matrix</Sub>
      <div style={{ border:"1px solid var(--dm-border)", borderRadius:12 }}>
        <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
          <thead><tr><Th c="Tier"/><Th c="Exemption"/><Th c="Investor type"/><Th c="Max raise"/><Th c="KYC required"/><Th c="KYB required"/></tr></thead>
          <tbody>
            {[
              ["Retail",         "—",       "Open",              "N/A",        "✓","—"],
              ["Accredited",     "Reg D",   "Accredited only",   "$Unlimited", "✓","—"],
              ["Institutional",  "Reg D §4","Qualified buyers",  "$Unlimited", "✓","✓"],
              ["Non-US",         "Reg S",   "Non-US persons",    "$Unlimited", "✓","✓ (entity)"],
            ].map(([tier,ex,inv,max,kyc,kyb],i,arr)=>(
              <tr key={tier} style={{ borderBottom:i<arr.length-1?"1px solid var(--dm-border)":"none" }}>
                <td style={{ padding:"11px 16px", fontWeight:700, color:"var(--dm-ink)" }}>{tier}</td>
                <td style={{ padding:"11px 16px", fontFamily:"monospace", fontSize:12, color:"#5A5BEB", background:"rgba(90,91,235,.03)" }}>{ex}</td>
                <td style={{ padding:"11px 16px", color:"var(--dm-muted)" }}>{inv}</td>
                <td style={{ padding:"11px 16px", fontFamily:"monospace", fontSize:12, color:"var(--dm-ink)" }}>{max}</td>
                <td style={{ padding:"11px 16px", textAlign:"center", color:kyc==="✓"?"#28A66B":"var(--dm-muted)", fontWeight:700 }}>{kyc}</td>
                <td style={{ padding:"11px 16px", textAlign:"center", color:kyb.startsWith("✓")?"#28A66B":"var(--dm-muted)", fontWeight:700 }}>{kyb}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ── CARD SYSTEM DOCUMENTATION ────────────────────────────────────────────────
function SectionCardSystem() {
  const TIERS = [
    {
      key: "surface",
      label: "Surface",
      tag: "CARD.surface",
      style: { background:"var(--dm-surface)", border:"1px solid var(--dm-border)", borderRadius:16, boxShadow:"0 1px 3px rgba(7,1,24,.06), 0 2px 8px rgba(7,1,24,.06)" },
      desc: "Default card on any background. The majority of UI cards, table rows, and list items.",
      specs: [["Background","var(--dm-surface)"],["Border","1px · var(--dm-border)"],["Radius","16px"],["Shadow","S1 — subtle"]],
      uses: ["Asset cards","Metric tiles","List items","Table rows"],
      dark: false,
    },
    {
      key: "raised",
      label: "Raised",
      tag: "CARD.raised",
      style: { background:"var(--dm-surface)", border:"1px solid var(--dm-border)", borderRadius:16, boxShadow:"0 1px 3px rgba(7,1,24,.04), 0 4px 12px rgba(7,1,24,.06), 0 8px 24px rgba(7,1,24,.05)" },
      desc: "Surface card pulled forward. Use when a card needs to stand out from its siblings.",
      specs: [["Background","var(--dm-surface)"],["Border","1px · var(--dm-border)"],["Radius","16px"],["Shadow","S2 — raised"]],
      uses: ["Active/selected card","Feature card","Pricing card","Modal dialog"],
      dark: false,
    },
    {
      key: "dark",
      label: "Dark",
      tag: "CARD.dark",
      style: { background:"#070118", border:"1px solid rgba(90,91,235,.15)", borderRadius:16, boxShadow:"0 1px 3px rgba(7,1,24,.04), 0 4px 12px rgba(7,1,24,.06), 0 8px 24px rgba(7,1,24,.05)" },
      desc: "Opaque dark card for use inside dark sections and the app sidebar.",
      specs: [["Background","#070118"],["Border","1px · violet .15"],["Radius","16px"],["Shadow","S2"]],
      uses: ["App sidebar panels","Dark section cards","Bento grid cells","Stat tiles"],
      dark: true,
    },
    {
      key: "glass",
      label: "Glass",
      tag: "CARD.glass",
      style: { background:"linear-gradient(135deg, rgba(90,91,235,.08) 0%, rgba(90,91,235,.03) 100%)", border:"1px solid rgba(90,91,235,.18)", borderRadius:16, boxShadow:"0 1px 3px rgba(7,1,24,.06), 0 2px 8px rgba(7,1,24,.06)" },
      desc: "Violet-tinted glass wash. Layered over dark backgrounds for depth and brand presence.",
      specs: [["Background","Violet glass wash .08→.03"],["Border","1px · violet .18"],["Radius","16px"],["Shadow","S1"]],
      uses: ["Floating overlays","Capability tiles","Tag/badge containers","Notification cards"],
      dark: false,
    },
    {
      key: "accent",
      label: "Accent",
      tag: "CARD.accent(color)",
      style: { background:"rgba(90,91,235,.07)", border:"1px solid rgba(90,91,235,.3)", borderRadius:16, boxShadow:"0 1px 3px rgba(7,1,24,.06), 0 2px 8px rgba(7,1,24,.06)", position:"relative", overflow:"hidden" },
      desc: "Glass card with a 3 px brand-coloured top stripe. One accent colour per card — never mix.",
      specs: [["Background","Accent glass .07"],["Border","1px · accent .30"],["Radius","16px"],["Stripe","3px top · solid accent"]],
      uses: ["Feature highlight","How-it-works steps","Icon+desc tiles","Governance proposals"],
      dark: false,
      stripe: "#5A5BEB",
    },
    {
      key: "section",
      label: "Section",
      tag: "CARD.section",
      style: { background:"var(--dm-surface)", border:"1px solid var(--dm-border)", borderRadius:20, boxShadow:"0 1px 3px rgba(7,1,24,.04), 0 4px 12px rgba(7,1,24,.06), 0 8px 24px rgba(7,1,24,.05)" },
      desc: "Outer section wrapper. Contains full component demos. Larger radius, S2 shadow.",
      specs: [["Background","var(--dm-surface)"],["Border","1px · var(--dm-border)"],["Radius","20px"],["Shadow","S2"]],
      uses: ["Section demo wrapper","Interactive demo","Comparison tables","Multi-step flows"],
      dark: false,
    },
  ];

  const SHADOW_TIERS = [
    { name:"S1 — Surface",   val:"0 1px 3px rgba(7,1,24,.06),\n0 2px 8px rgba(7,1,24,.06)",   use:"Default card resting state" },
    { name:"S2 — Raised",    val:"0 4px 16px rgba(7,1,24,.1),\n0 8px 24px rgba(7,1,24,.08)", use:"Elevated panels, active cards" },
    { name:"S3 — Prominent", val:"0 2px 4px rgba(7,1,24,.04), 0 6px 20px rgba(7,1,24,.07), 0 16px 40px rgba(7,1,24,.07)",                                use:"Section wrappers, dark hero panels" },
  ];

  return (
    <div>
      <SectionLabel eyebrow="Brand" title="Card System"
        desc="Six named card tiers define every surface in DEFACTOR. Import from the CARD constant — never compose card styles inline. Consistent radius, shadow, border, and glass wash rules create a coherent depth language across the product." />

      {/* Tier grid */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:16, marginBottom:40 }}>
        {TIERS.map(t => (
          <div key={t.key} style={{ ...t.style, padding:24, position:"relative" }}>
            {t.stripe && <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:t.stripe, borderRadius:"16px 16px 0 0" }} />}
            {/* Header */}
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:12 }}>
              <span style={{ fontSize:15, fontWeight:700, color: t.dark?"#F0F0FD":"var(--dm-ink)", letterSpacing:"-.01em" }}>{t.label}</span>
              <code style={{ fontSize:10, fontFamily:"monospace", padding:"3px 8px", borderRadius:6,
                background: t.dark?"rgba(90,91,235,.15)":"rgba(90,91,235,.08)",
                color:"#8182EF", border:"1px solid rgba(90,91,235,.2)" }}>{t.tag}</code>
            </div>
            <p style={{ fontSize:12, color: t.dark?"rgba(240,240,253,.55)":"var(--dm-muted)", lineHeight:1.6, marginBottom:16 }}>{t.desc}</p>

            {/* Spec table */}
            <div style={{ display:"flex", flexDirection:"column", gap:5, marginBottom:16 }}>
              {t.specs.map(([k,v])=>(
                <div key={k} style={{ display:"flex", justifyContent:"space-between", fontSize:11, padding:"5px 0",
                  borderBottom:`1px solid ${t.dark?"rgba(255,255,255,.05)":"var(--dm-divider)"}` }}>
                  <span style={{ color: t.dark?"rgba(240,240,253,.4)":"var(--dm-muted)", fontWeight:600 }}>{k}</span>
                  <span style={{ color: t.dark?"rgba(240,240,253,.8)":"var(--dm-ink)", fontFamily:"monospace", fontSize:10 }}>{v}</span>
                </div>
              ))}
            </div>

            {/* Use cases */}
            <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
              {t.uses.map(u=>(
                <span key={u} style={{ fontSize:10, padding:"3px 8px", borderRadius:100, fontWeight:600,
                  background: t.dark?"rgba(255,255,255,.06)":"rgba(90,91,235,.07)",
                  color: t.dark?"rgba(240,240,253,.6)":"#5A5BEB",
                  border: t.dark?"1px solid rgba(255,255,255,.08)":"1px solid rgba(90,91,235,.15)" }}>{u}</span>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Shadow tier reference */}
      <Sub>Shadow Tiers</Sub>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:16, marginBottom:40 }}>
        {SHADOW_TIERS.map(s=>(
          <div key={s.name} style={{ background:"var(--dm-surface)", border:"1px solid var(--dm-border)", borderRadius:16, padding:24, boxShadow:s.val.replace(/\n/g,"") }}>
            <p style={{ fontSize:13, fontWeight:700, color:"var(--dm-ink)", marginBottom:6 }}>{s.name}</p>
            <code style={{ fontSize:10, fontFamily:"monospace", color:"#5A5BEB", display:"block", lineHeight:1.7, whiteSpace:"pre", marginBottom:10 }}>{s.val}</code>
            <p style={{ fontSize:11, color:"var(--dm-muted)" }}>{s.use}</p>
          </div>
        ))}
      </div>

      {/* Border radius scale */}
      <Sub>Border Radius Scale</Sub>
      <div style={{ display:"flex", gap:16, flexWrap:"wrap", marginBottom:40, alignItems:"flex-end" }}>
        {[[4,"Micro\ntag",48],[8,"Input\nbadge",48],[10,"Icon\ntile",48],[12,"Sub-card\nlist item",48],[16,"Card",56],[20,"Section",64],[100,"Pill\nbutton",80]].map(([r,lbl,w])=>(
          <div key={r} style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:10 }}>
            <div style={{ width:w, height:40,
              background:"var(--dm-surface)", border:"2px solid #5A5BEB",
              borderRadius:r, boxShadow:"0 1px 3px rgba(7,1,24,.06), 0 2px 8px rgba(7,1,24,.06)" }} />
            <div style={{ textAlign:"center" }}>
              <p style={{ fontSize:12, fontWeight:700, color:"var(--dm-ink)" }}>{r}px</p>
              <p style={{ fontSize:9, color:"var(--dm-muted)", whiteSpace:"pre", textAlign:"center", lineHeight:1.4 }}>{lbl}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Rules with Do / Don't headers */}
      <Sub>Rules</Sub>
      {(()=>{
        const CARD_RULES = [
          [true,  "Surface card on light page — CARD.surface with S1 shadow"],
          [true,  "Dark section card — CARD.dark with violet border at .15 opacity"],
          [true,  "Accent tile — CARD.accent(color) + 3px top stripe, one colour only"],
          [true,  "Section wrapper — borderRadius:20, S2 shadow, no overflow:hidden"],
          [false, "Custom border-radius outside the 8-step scale"],
          [false, "overflow:hidden on an element that also has boxShadow"],
          [false, "Mixing card tiers on the same hierarchy level"],
          [false, "Inline shadow values — always reference S1 / S2 / S3"],
        ];
        return (
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16 }}>
            <div>
              <p style={{ fontSize:11, fontWeight:700, color:"#28A66B", textTransform:"uppercase", letterSpacing:".1em", marginBottom:10 }}>✓ Do</p>
              <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                {CARD_RULES.filter(([ok])=>ok).map(([,rule])=>(
                  <div key={rule} style={{ display:"flex", gap:12, padding:"12px 14px", borderRadius:12, background:"rgba(40,166,107,.04)", border:"1px solid rgba(40,166,107,.2)" }}>
                    <span style={{ fontSize:13, fontWeight:700, color:"#28A66B", flexShrink:0 }}>✓</span>
                    <span style={{ fontSize:12, color:"var(--dm-ink)", lineHeight:1.5 }}>{rule}</span>
                  </div>
                ))}
              </div>
            </div>
            <div>
              <p style={{ fontSize:11, fontWeight:700, color:"#D3194E", textTransform:"uppercase", letterSpacing:".1em", marginBottom:10 }}>✕ Don't</p>
              <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                {CARD_RULES.filter(([ok])=>!ok).map(([,rule])=>(
                  <div key={rule} style={{ display:"flex", gap:12, padding:"12px 14px", borderRadius:12, background:"rgba(211,25,78,.04)", border:"1px solid rgba(211,25,78,.18)" }}>
                    <span style={{ fontSize:13, fontWeight:700, color:"#D3194E", flexShrink:0 }}>✕</span>
                    <span style={{ fontSize:12, color:"var(--dm-ink)", lineHeight:1.5 }}>{rule}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        );
      })()}
    </div>
  );
}
